/**
 * Header — MUI AppBar with branding, theme toggle, notifications, and user menu.
 * @accessibility Semantic AppBar as header. All controls are keyboard-navigable with visible focus.
 * Notification count driven by event bus — reacts to cross-MFE events in real time.
 */
import React, { useState } from 'react';
import AppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import IconButton from '@mui/material/IconButton';
import Box from '@mui/material/Box';
import Tooltip from '@mui/material/Tooltip';
import Badge from '@mui/material/Badge';
import DarkModeIcon from '@mui/icons-material/DarkMode';
import LightModeIcon from '@mui/icons-material/LightMode';
import NotificationsIcon from '@mui/icons-material/Notifications';
import { useThemeMode, themeTokens } from '@shared/ui-components';
import { AppEvent, useEventBus } from '@shared/event-bus';

const Header: React.FC = () => {
  const { themeMode, toggleTheme } = useThemeMode();
  const [notificationCount, setNotificationCount] = useState(0);

  /** Increment badge for any notification-generating event */
  useEventBus(AppEvent.NotificationReceived, () => {
    setNotificationCount((prev) => prev + 1);
  });
  useEventBus(AppEvent.IncidentCreated, () => {
    setNotificationCount((prev) => prev + 1);
  });
  useEventBus(AppEvent.RiskUpdated, () => {
    setNotificationCount((prev) => prev + 1);
  });

  const notificationLabel = notificationCount === 0
    ? 'No new notifications'
    : `${notificationCount} unread notification${notificationCount !== 1 ? 's' : ''}`;

  return (
    <AppBar
      component="header"
      position="fixed"
      elevation={0}
      sx={{ zIndex: (theme) => theme.zIndex.drawer + 1, height: `${themeTokens.layout.headerHeight}px`, justifyContent: 'center' }}
    >
      <Toolbar sx={{ minHeight: `${themeTokens.layout.headerHeight}px !important`, px: 2 }}>
        {/* Brand */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mr: 'auto' }}>
          {/* Accenture logo mark — filled ">" chevron */}
          <Box
            component="svg"
            viewBox="0 0 18 26"
            aria-hidden="true"
            sx={{ width: 16, height: 16, flexShrink: 5 }}
          >
            <path d="M0 0 L14 13 L0 26 L4.5 26 L18 13 L4.5 0 Z" fill="#a100ff" />
          </Box>
          <Typography variant="h6" component="span" sx={{ fontWeight: 700, fontSize: '1rem', letterSpacing: '-0.01em', color: '#f8fafc' }}>
            Accenture Risk &amp; Compliance
          </Typography>
        </Box>

        {/* Right Controls */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
          <Tooltip title={`Switch to ${themeMode === 'dark' ? 'light' : 'dark'} mode`}>
            <IconButton aria-label={`Switch to ${themeMode === 'dark' ? 'light' : 'dark'} mode`} onClick={toggleTheme} size="small" sx={{ color: '#cbd5e1' }}>
              {themeMode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
            </IconButton>
          </Tooltip>

          <Tooltip title={notificationLabel}>
            <IconButton
              aria-label={notificationLabel}
              size="small"
              sx={{ color: '#cbd5e1' }}
              onClick={() => setNotificationCount(0)}
            >
              <Badge badgeContent={notificationCount > 0 ? notificationCount : undefined} color="error" max={99}>
                <NotificationsIcon fontSize="small" />
              </Badge>
            </IconButton>
          </Tooltip>
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Header;
